begin;
-- retire the auto-mistitled row (cir_26_… was parsed as 'Circular 26'; it is Circular 03 of 2026)
delete from regulations where slug = 'dgms-tech-circular-26-of-2026-30-06-2026';

insert into regulations (slug, title, category, summary, doc_number, authority, issued_date, status, status_note, source_url, source_filename, relevance, sort_order, published, featured, file_size_kb, download_url) values ('dgms-tech-circular-03-2026-dust-suppression-additives', 'DGMS (Tech) Circular 03 of 2026 — Standard properties of chemical additives for dust suppression in coal mines', 'dgms_circular', 'Addressed to the owner, agent and manager of all coal mines and to manufacturers. It modifies Para 2(i) of DGMS Circular (Approval) No. 06 of 24 February 2015 so that the standard properties of chemical additives used as dust suppressants may be tested at other Government laboratories and test houses — not only at the four institutions named earlier (National Chemical Laboratory Pune, Industrial Toxicology Research Centre Lucknow, Indian School of Mines Dhanbad and CIMFR Dhanbad). The aim is to keep toxic and hazardous chemicals out of dust-suppression materials.', 'DGMS/S&T/Tech.Cir/(Approval) No. 03', 'DGMS', '2026-06-29', 'in_force', null, 'https://www.dgms.gov.in/writereaddata/UploadFile/cir_26_30062026.pdf', 'cir_26_30062026.pdf', 3, 230, true, false, 171, 'https://docs.mangalamcoal.com/regs/dgms-tech-circular-03-2026-dust-suppression-additives.pdf')
  on conflict (slug) do update set title = excluded.title, category = excluded.category, summary = excluded.summary, doc_number = excluded.doc_number, authority = excluded.authority, issued_date = excluded.issued_date, status = excluded.status, status_note = excluded.status_note, source_url = excluded.source_url, source_filename = excluded.source_filename, relevance = excluded.relevance, sort_order = excluded.sort_order, published = excluded.published, featured = excluded.featured, file_size_kb = excluded.file_size_kb, download_url = excluded.download_url;
insert into regulations (slug, title, category, summary, doc_number, authority, issued_date, status, status_note, source_url, source_filename, relevance, sort_order, published, featured, file_size_kb, download_url) values ('dgms-tech-circular-04-2026-system-capacitive-current', 'DGMS (Tech) Circular 04 of 2026 — System capacitive current in restricted neutral power supply in mines', 'dgms_circular', 'Addressed to owners, agents and managers of all mines. Citing a rising trend of electrical accidents — seven lives lost and four serious injuries in 2025 alone — DGMS requires the system capacitive current to be taken into account in restricted-neutral power-supply systems, and calls for a review of electrical safety management alongside strict compliance with Regulation 103(1) of the CEA (Safety and Electric Supply) Regulations, 2023.', 'DGMS (Tech) Circular No. 04 of 2026', 'DGMS', '2026-07-14', 'in_force', null, 'https://www.dgms.gov.in/writereaddata/UploadFile/CircularTechnical2026_16072026.pdf', 'CircularTechnical2026_16072026.pdf', 3, 230, true, false, 395, 'https://docs.mangalamcoal.com/regs/dgms-tech-circular-04-2026-system-capacitive-current.pdf')
  on conflict (slug) do update set title = excluded.title, category = excluded.category, summary = excluded.summary, doc_number = excluded.doc_number, authority = excluded.authority, issued_date = excluded.issued_date, status = excluded.status, status_note = excluded.status_note, source_url = excluded.source_url, source_filename = excluded.source_filename, relevance = excluded.relevance, sort_order = excluded.sort_order, published = excluded.published, featured = excluded.featured, file_size_kb = excluded.file_size_kb, download_url = excluded.download_url;
insert into regulations (slug, title, category, summary, doc_number, authority, issued_date, status, status_note, source_url, source_filename, relevance, sort_order, published, featured, file_size_kb, download_url) values ('gsr-571-2026-rescue-station-equipment', 'G.S.R. 571(E) — Apparatus and equipment to be maintained at rescue stations and rescue rooms', 'dgms_notification', 'Specifies, under rule 131(1) of the OSH&WC (Central) Rules 2026, the apparatus and equipment that must be provided and kept ready for immediate use at a rescue station and rescue room — including breathing apparatus, absorbent charges, resuscitating apparatus, testing devices and flame safety lamps, with minimum quantities for each.', 'G.S.R. 571(E)', 'DGMS', '2026-07-01', 'in_force', 'Made under the Occupational Safety, Health and Working Conditions (Central) Rules, 2026.', 'https://www.dgms.gov.in/writereaddata/UploadFile/GA_4_16072026.pdf', 'GA_4_16072026.pdf', 2, 320, true, false, 320, 'https://docs.mangalamcoal.com/regs/gsr-571-2026-rescue-station-equipment.pdf')
