-- de-duplicate the OSH&WC (Central) Rules 2026 (same instrument catalogued twice):
-- enrich the canonical row, retire the DGMS-copy duplicate.
update regulations set
     doc_number = 'G.S.R. 345(E)',
     issued_date = '2026-05-08',
     status_note = 'Notified 8 May 2026 under Sections 133-134 of the OSH&WC Code 2020. Supersedes the Mines Rules 1955, Mines Rescue Rules 1985 and Mines Vocational Training Rules 1966, among others.',
     summary = 'The final Central Rules under the OSH&WC Code 2020, notified as G.S.R. 345(E) on 8 May 2026. For mines the Central Government is the appropriate Government, so these Rules apply directly. They prescribe working conditions, welfare facilities, safety committees, health and working-hours requirements and employer duties, and supersede a long list of earlier rules including the Mines Rules 1955, the Mines Rescue Rules 1985 and the Mines Vocational Training Rules 1966.'
   where slug = 'oshwc-code-central-rules-2026';
update regulations set published = false, status_note = 'Duplicate of oshwc-code-central-rules-2026 (same instrument, DGMS copy) — unpublished to avoid a double entry.' where slug = 'osh-wc-central-rules-2026-dgms-copy-12-05-2026';

-- normalise DD-MM-YYYY dates to ISO so they sort correctly
update regulations
     set issued_date = substring(issued_date from 7 for 4) || '-' || substring(issued_date from 4 for 2) || '-' || substring(issued_date from 1 for 2)
   where issued_date ~ '^\d{2}-\d{2}-\d{4}$';
commit;
